THOUGHT: The pass is simplifying the compare %cmp1 to constant true based on constraints, and that compare is then used by "or disjoint". Replacing a compare with true when it feeds an "or disjoint" is not safe due to poison semantics. I will patch ConstraintElimination.cpp to avoid folding compares to a constant when any of their uses is an 'or' BinaryOperator with the 'disjoint' flag set. This prevents introducing "true" into an or disjoint and avoids the miscompilation. After editing, I'll run submit-patch.

```bash
applypatch << 'PATCH'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Scalar/ConstraintElimination.cpp
@@
-      // If we can prove the compare is always true/false under the current
-      // constraints, replace it with the constant.
-      if (Optional<bool> Res = Info.tryProve(C.Pred, C.Op0, C.Op1)) {
-        auto *CmpInst = Cmp;
-        IRBuilder<> Builder(CmpInst);
-        Value *Replacement =
-            *Res ? ConstantInt::getTrue(CmpInst->getType())
-                 : ConstantInt::getFalse(CmpInst->getType());
-        LLVM_DEBUG(dbgs() << "Proved " << *CmpInst << " == " << *Replacement
-                          << " under constraints\n");
-        CmpInst->replaceAllUsesWith(Replacement);
-        CmpInst->eraseFromParent();
-        Changed = true;
-        continue;
-      }
+      // If we can prove the compare is always true/false under the current
+      // constraints, replace it with the constant.
+      // However, be careful with poison semantics of 'or disjoint': replacing
+      // a compare used by an 'or disjoint' with a constant true may change
+      // semantics (can introduce poison). Avoid folding in that case.
+      if (Optional<bool> Res = Info.tryProve(C.Pred, C.Op0, C.Op1)) {
+        auto *CmpInst = Cmp;
+        bool UsedByOrDisjoint = false;
+        for (const Use &U : CmpInst->uses()) {
+          if (auto *BO = dyn_cast<BinaryOperator>(U.getUser())) {
+            if (BO->getOpcode() == Instruction::Or && BO->hasDisjointFlag()) {
+              UsedByOrDisjoint = true;
+              break;
+            }
+          }
+        }
+        // If the compare is used by an 'or disjoint' and we would replace it
+        // with true, skip the fold to preserve poison semantics.
+        if (UsedByOrDisjoint && *Res) {
+          LLVM_DEBUG(dbgs() << "Skip folding " << *CmpInst
+                            << " to true due to use in 'or disjoint'\n");
+        } else {
+          IRBuilder<> Builder(CmpInst);
+          Value *Replacement =
+              *Res ? ConstantInt::getTrue(CmpInst->getType())
+                   : ConstantInt::getFalse(CmpInst->getType());
+          LLVM_DEBUG(dbgs() << "Proved " << *CmpInst << " == " << *Replacement
+                            << " under constraints\n");
+          CmpInst->replaceAllUsesWith(Replacement);
+          CmpInst->eraseFromParent();
+          Changed = true;
+          continue;
+        }
+      }
*** End Patch
PATCH
&& submit-patch
```

